// 1. 取得 JSON 資料
let inputData = $input.first().json;
let data = inputData.original_data || inputData;
let finalMessage = "";

// 2. 判斷 details 是否存在且有內容
if (data.details && Array.isArray(data.details) && data.details.length > 0) {

    // 【關鍵修改】改為偵測「使用者的原始輸入」是否有中文，而不是偵測 AI 的回覆
    let userMessage = "";
    try {
        userMessage = $('Webhook').item.json.body.data.message.conversation || "";
    } catch(e) {
        userMessage = data.agent_reply || "";
    }
    const isChinese = /[\u4e00-\u9fa5]/.test(userMessage);

    // 取得現在時間並格式化
    const now = new Date();
    now.setHours(now.getHours() + 8); 

    const year = now.getUTCFullYear();
    const month = now.getUTCMonth() + 1;
    const day = now.getUTCDate();
    let hours = now.getUTCHours();
    const minutes = now.getUTCMinutes().toString().padStart(2, '0');
    const seconds = now.getUTCSeconds().toString().padStart(2, '0');

    const ampmEN = hours >= 12 ? 'PM' : 'AM';
    const ampmZH = hours >= 12 ? '下午' : '上午';
    let hours12 = hours % 12;
    hours12 = hours12 ? hours12 : 12;

    const dateStrZH = `${year}年${month}月${day}日 ${ampmZH}${hours12}:${minutes}:${seconds}`;
    const dateStrEN = `${year}/${month}/${day} ${hours12}:${minutes}:${seconds}${ampmEN}`;

    let totalCal = 0, totalFat = 0, totalPro = 0, totalCarb = 0, totalFib = 0;
    let itemsText = "";

    data.details.forEach(item => {
        let meal = item.meal_time ? item.meal_time.toLowerCase() : "snack";
        let foodName = isChinese ? (item.food_name || item.food_name_en) : (item.food_name_en || item.food_name);

        let cal = item.nutrition?.calories || 0;
        let fat = item.nutrition?.fat || 0;
        let pro = item.nutrition?.protein || 0;
        let carb = item.nutrition?.carbohydrates || 0;
        let fib = item.nutrition?.fiber || 0;

        totalCal += cal; totalFat += fat; totalPro += pro; totalCarb += carb; totalFib += fib;

        const fmt = (num) => Math.round(num * 10) / 10;

        if (isChinese) {
            const mealMapZH = { breakfast: '早餐', lunch: '午餐', dinner: '晚餐', snack: '小食' };
            meal = mealMapZH[meal] || meal;
            itemsText += `- ${meal}: ${foodName} (卡路里: ${fmt(cal)} kcal, 脂肪: ${fmt(fat)}g, 蛋白質: ${fmt(pro)}g, 碳水化合物: ${fmt(carb)}g, 纖維: ${fmt(fib)}g)\n`;
        } else {
            const mealMapEN = { breakfast: 'Breakfast', lunch: 'Lunch', dinner: 'Dinner', snack: 'Snack' };
            meal = mealMapEN[meal] || meal.charAt(0).toUpperCase() + meal.slice(1);
            itemsText += `- ${meal}: ${foodName} (Calories: ${fmt(cal)} kcal, Fats: ${fmt(fat)}g, Protein: ${fmt(pro)}g, Carbs: ${fmt(carb)}g, Fiber: ${fmt(fib)}g)\n\n`;
        }
    });

    const fmtTotal = (num) => Math.round(num * 10) / 10;

    if (isChinese) {
        finalMessage = `你嘅紀錄已經存檔在 ${dateStrZH}。\n\n紀錄內容:\n${itemsText}\n- 總計: (卡路里: ${fmtTotal(totalCal)} kcal, 脂肪: ${fmtTotal(totalFat)}g, 蛋白質: ${fmtTotal(totalPro)}g, 碳水化合物: ${fmtTotal(totalCarb)}g, 纖維: ${fmtTotal(totalFib)}g)`;
    } else {
        itemsText = itemsText.trimEnd();
        finalMessage = `Your record has been saved at ${dateStrEN}:\n\n${itemsText}\n\n- Total: (Calories: ${fmtTotal(totalCal)} kcal, Fats: ${fmtTotal(totalFat)}g, Protein: ${fmtTotal(totalPro)}g, Carbs: ${fmtTotal(totalCarb)}g, Fiber: ${fmtTotal(totalFib)}g)`;
    }

} else {
    finalMessage = data.agent_reply || "已收到您的訊息。 / Message received.";
}

return [{
    json: {
        reply_text: finalMessage,
        original_data: inputData
    }
}];

// 1. 取得上一個節點傳進來的資料
const inputData = $input.first().json;

// 2. 提取準備要發送的回覆內容
const replyText = inputData.reply_text || "";

// 3. 語言偵測 (檢查回覆內容中是否包含中文字)
const hasHanzi = /[\u4e00-\u9fa5]/.test(replyText);

let language = "English";
if (hasHanzi) {
    language = "Chinese";
}

// 4. 輸出結果給下一個節點 (HTTP Request)
return [{
    json: {
        language: language,
        reply: replyText
    }
}];

// 1. 取得 AI Agent 的輸出文字
let aiContent = $input.first().json.output || "";

// 2. 尋找 JSON 的大括號範圍
let startIndex = aiContent.indexOf('{');
let endIndex = aiContent.lastIndexOf('}');

let parsedData = {};

// 3. 判斷是否有 JSON 格式
if (startIndex !== -1 && endIndex !== -1 && endIndex > startIndex) {
    // 【情況 A：有找到 JSON】嘗試擷取並解析
    let jsonString = aiContent.substring(startIndex, endIndex + 1);
    try {
        parsedData = JSON.parse(jsonString);

        // 檢查 AI 是否有把回覆寫在 JSON 外面（前面）
        let replyText = aiContent.substring(0, startIndex).trim();
        // 清理開頭可能多出的引號或反斜線
        replyText = replyText.replace(/^"+|"+$/g, '').trim();

        if (!parsedData.agent_reply) {
            parsedData.agent_reply = replyText || "已為您記錄。";
        }
    } catch (error) {
        // 萬一 JSON 格式壞掉解析失敗的備用方案
        parsedData = { 
            summary: "JSON 解析失敗", 
            details: [],
            agent_reply: aiContent 
        };
    }
} else {
    // 【情況 B：完全沒有 JSON (純聊天 / AI 追問)】
    // 也就是您截圖中遇到的情況，我們不報錯，而是把 AI 說的話直接存起來
    parsedData = {
        summary: "Chat Only",
        details: [],
        agent_reply: aiContent.trim() 
    };
}

// 4. 回傳給下一個節點 (n8n 標準格式)
return [ { json: parsedData } ];
